query:
SELECT propertyType, tag, COUNT(*) as count FROM properties GROUP BY propertyType, tag ORDER BY propertyType, tag;
SELECT COUNT(*) as total_with_images FROM properties WHERE imageUrl IS NOT NULL AND imageUrl != '';
SELECT COUNT(*) as total FROM properties;

